import { readFileSync, writeFileSync } from 'fs';
import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { checkpoint, restore } from '@tigrisdata/agent-kit';
import { execSync } from 'child_process';

async function main() {
  try {
    const trialId = readFileSync('/logs/artifacts/trial_id', 'utf-8').trim();
    const bucketName = `harbor-awscli-${trialId}`.toLowerCase().replace(/[^a-z0-9.-]/g, '-');

    const s3 = new S3Client({
      endpoint: 'REDACTED',
      region: 'REDACTED',
      credentials: {
        accessKeyId: process.env.TIGRIS_STORAGE_ACCESS_KEY_ID!,
        secretAccessKey: process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY!
      }
    });

    // 1. Upload v1.txt
    await s3.send(new PutObjectCommand({
      Bucket: bucketName,
      Key: 'v1.txt',
      Body: 'version=1'
    }));
    console.log('Uploaded v1.txt with version=1');

    // 2. Checkpoint
    const ckptRes = await checkpoint(bucketName, { name: 'before-mutation' });
    if (ckptRes.error) {
      console.error('Checkpoint failed:', ckptRes.error);
      process.exit(1);
    }
    const ckpt = ckptRes.data;
    console.log('Checkpoint created:', ckpt.snapshotId);

    // 3. Mutate
    await s3.send(new PutObjectCommand({
      Bucket: bucketName,
      Key: 'v1.txt',
      Body: 'version=2'
    }));
    console.log('Uploaded v1.txt with version=2');

    // 4. Restore
    const restoreRes = await restore(bucketName, ckpt.snapshotId, { forkName: 'rollback-recovery' });
    if (restoreRes.error) {
      console.error('Restore failed:', restoreRes.error);
      process.exit(1);
    }
    const restored = restoreRes.data;
    console.log('Restored to fork:', restored.bucket);

    writeFileSync('/home/user/chained-ckpt/recovery.json', JSON.stringify({ recoveryBucket: restored.bucket }));

    // 5. Tear down
    console.log('Deleting recovery bucket...');
    execSync(`tigris buckets delete ${restored.bucket}`, { stdio: 'inherit' });
    console.log('Done');
    process.exit(0);

  } catch (err) {
    console.error('Error:', err);
    process.exit(1);
  }
}

main();

import { createBucket } from "@tigrisdata/storage";

async function run() {
  const res = await createBucket("harbor-awscli-chained-checkpoint-restoration--aqmmgss", { enableSnapshot: true });
  console.log(res);
}
run();

